local LxBehaviour = require("LApp.component.LxBehaviour")
---@class LxBaseAdapter:LxBehaviour
local LxBaseAdapter = classX("LxBaseAdapter", LxBehaviour)

local SCENE_CAMERA_NAME = "SceneCamera"
local MAIN_CAMERA_NAME = "MainCamera"

local CS = CS
local typeof = typeof
local UnityEngine = UnityEngine
local typeofCamera = typeof(UnityEngine.Camera)
local typeofCustomAxis = typeof(CardEHT.YXTileMapCustomAxis)

function LxBaseAdapter:Initialize()
    self._param = nil
    self._mapGo = nil

    self._adapterName = ""

    ---@type LxResRequester
    self._levelResRequester = nil
    ---@type table<string, LxResRequester>
    self._mapResRequester = {}

    self._sceneName = nil
    self._sceneArgList = nil

    self._sceneMainRoot = nil
    self._sceneCameraRoot = nil
    self._sceneMainCamera = nil

    self._sceneLoadedBeginTime = nil

    self._cameraAdaptOffset = nil 	-- scene orthographicSize adapt offset
    self._bCameraAdapt = nil 		-- scene orthographicSize adapt
    self._sceneCustomAxis = nil

    self._cameraAxisX = 0
    self._cameraAxisY = 0
    self._cameraAxisZ = 1
end

function LxBaseAdapter:ResetParamEnv()
    self._sceneArgList = nil

    self._sceneMainRoot = nil
    self._sceneCameraRoot = nil
    self._sceneMainCamera = nil

    self._sceneLoadedBeginTime = nil

    self._cameraAdaptOffset = nil 	-- scene orthographicSize adapt offset
    self._bCameraAdapt = nil 		-- scene orthographicSize adapt
    self._sceneCustomAxis = nil
end

---场景加载完成事件之后进入 AfterLevelLoaded之前调用
function LxBaseAdapter:OnLevelLoaded()
    self._sceneLoadedBeginTime = Time.realtimeSinceStartup

    GF.CleanUpWnd()

    if (not self:InitSceneBase()) then
        return
    end

    self:OnCameraAdapt()

    -- 初始化Post
    gLGamePostProcess:InitPostProcess()
end

