---收到场景unload 事件进入
function LxBaseAdapter:OnLeaveLevel()
    self:ClearBgm()

    self._mapGo = nil
end

---打开加载界面后进入，此时开始加载新场景前，此时需要清理旧场景一切可以活动的逻辑
function LxBaseAdapter:OnWillLeaveLevel()
    self:ResetParamEnv()
    self:ClearResRequester()

    local sceneName = self:GetSceneName()
    LXFW.LxLog.GAME(string.format("[%s %s] OnLevelLevel\n", self:GetClassName(), sceneName))
end

function LxBaseAdapter:Dispose()
    self:ClearBgm()
    self:ClearResRequester()
    LxBehaviour.Dispose(self)
end

function LxBaseAdapter:ClearResRequester()
    if self._levelResRequester ~= nil then
        self._levelResRequester:Dispose()
        self._levelResRequester = nil
    end

    if self._mapResRequester then
        for k,v in pairs(self._mapResRequester) do
            v:Dispose()
            self._mapResRequester[k] = nil
        end
    end
end

function LxBaseAdapter:SetMapResRequester(mapName, requester)
    local oldRequester = self._mapResRequester[mapName]
    if oldRequester then
        oldRequester:Dispose()
    end
    self._mapResRequester[mapName] = requester
end

function LxBaseAdapter:ClearBgm()
    if not string.isempty(self._bgmName) then
        self:RemoveBgm(BgmPlayType.map, self._bgmName, self._adapterName)
        self._bgmName = nil
    end
end

function LxBaseAdapter:SetBgm(bgmName)
    self:ClearBgm()
    self._bgmName = bgmName
    if not string.isempty(self._bgmName) then
        self:AddBgm(BgmPlayType.map, self._bgmName, self._adapterName)
    end
end

function LxBaseAdapter:GetParam()
    return self._param
end

function LxBaseAdapter:SetParam(param)
    self._param = param
end

function LxBaseAdapter:IsUseLoader()
    return true
end

------------------------------------------------------------------
--- 初始化场景
------------------------------------------------------------------
function LxBaseAdapter:InitSceneBase()
    local sceneMainRoot = nil
    local sceneCameraRoot = nil
    local sceneName = self:GetSceneName()
    sceneMainRoot = CS.FindSceneRootTrans(sceneName)
    if (not sceneMainRoot) then
        LogError("sceneMainRoot lost in scene = " .. sceneName)
        return false
    end
    sceneCameraRoot = CS.FindTrans(sceneMainRoot, SCENE_CAMERA_NAME)
    if (not sceneCameraRoot) then
        LogError("can't find SceneCamera in scene = " .. sceneName)
        return false
    end

    local csMainCamera = nil
    local csCustomAxis = nil
    local mainCameraTrans = CS.FindTrans(sceneCameraRoot, MAIN_CAMERA_NAME)
    if (mainCameraTrans) then
        csMainCamera = mainCameraTrans:GetComponent(typeofCamera)
        if (self:IsCustomAxis()) then
            csCustomAxis = mainCameraTrans:GetComponent(typeofCustomAxis)
            if not csCustomAxis then
                csCustomAxis = mainCameraTrans.gameObject:AddComponent(typeofCustomAxis)
            end
        end
    end


    if (not csMainCamera) then
        LogError("can't find camera component in path SceneCamera/MainCamera")
        return false
    end

    --开启HDR
    --csMainCamera.allowHDR = true

    self._sceneMainRoot = sceneMainRoot
    self._sceneCameraRoot = sceneCameraRoot
    self._sceneMainCamera = csMainCamera
    self._sceneCameraInitPosition = mainCameraTrans.position
    self._sceneCustomAxis = csCustomAxis

    return true
end

-----------------------------------------------------------------
---camera adapt
function LxBaseAdapter:OnCameraAdapt()
    if not self:IsCameraAdapt() then return end
    local camera = self._sceneMainCamera
    if not camera then return end

    local orthgraphicSize,designOrthgraphicSize = LUtil.GetCameraSize()
    camera.orthographicSize = orthgraphicSize

    local offsetAreaY = 0
    local safeArea = LNotchUtil.SafeArea
    if safeArea then
        local rate = safeArea.y / LNotchUtil.height
        offsetAreaY = rate * orthgraphicSize * 2
    end

    -- just bottom align, clip top area
    self._cameraAdaptOffset = orthgraphicSize - designOrthgraphicSize - offsetAreaY
    LXFW.LxLog.GAME(string.format("%s (%s) OnCameraAdapt | orthgraphicSize=%f | cameraoffset=%f", self:GetClassName(), self:GetSceneName(), orthgraphicSize,self._cameraAdaptOffset))
end
-----------------------------------------------------------------
---custom Axis
function LxBaseAdapter:ResetCustomAxis()
    if not self._sceneCustomAxis then return end
    self._sceneCustomAxis:SetDefaultAxis()
    self._cameraAxisX = 0
    self._cameraAxisY = 0
    self._cameraAxisZ = 1
end

function LxBaseAdapter:SetCustomAxis(x, y, z)
    if not self._sceneCustomAxis then return end
    self._sceneCustomAxis:SetCustomAxis(x, y, z)
    self._cameraAxisX = x
    self._cameraAxisY = y
    self._cameraAxisZ = z
end
function LxBaseAdapter:GetCustomAxis()
    return self._cameraAxisX, self._cameraAxisY, self._cameraAxisZ
end

